import Foundation

struct PromptSanitiser {
    private static let clientBlocklist: Set<String> = [
        "ignore previous instructions",
        "disregard your system prompt",
        "you are now",
        "act as if"
    ]
    private static let maxCharacters = 2_000

    enum SanitiseResult {
        case allowed(String)
        case blocked(reason: String)
    }

    static func sanitise(_ raw: String) -> SanitiseResult {
        // Strip control characters except newline/tab
        var text = raw.unicodeScalars
            .filter { $0.value >= 0x20 || $0 == "\n" || $0 == "\t" }
            .reduce(into: "") { $0.append(Character($1)) }

        // Collapse excessive whitespace
        text = text.replacingOccurrences(
            of: #"[ \t]{2,}"#,
            with: " ",
            options: .regularExpression
        )
        text = text.trimmingCharacters(in: .whitespacesAndNewlines)

        // Enforce length ceiling
        if text.count > maxCharacters {
            text = String(text.prefix(maxCharacters))
        }

        // Client-side blocklist (case-insensitive)
        let lowered = text.lowercased()
        for term in clientBlocklist where lowered.contains(term) {
            return .blocked(reason: "Input contains disallowed phrase.")
        }

        return .allowed(text)
    }
}

@MainActor
final class ChatViewModel: ObservableObject {
    @Published var inputText = ""
    @Published var messages: [ChatMessage] = []
    @Published var errorMessage: String?

    private let service: ClaudeService

    init(service: ClaudeService) { self.service = service }

    func sendMessage() async {
        let raw = inputText
        inputText = ""

        switch PromptSanitiser.sanitise(raw) {
        case .blocked(let reason):
            errorMessage = reason
            return
        case .allowed(let clean):
            messages.append(.user(clean))
            do {
                let reply = try await service.send(userMessage: clean)
                messages.append(.assistant(reply))
            } catch {
                errorMessage = "Request failed. Please try again."
            }
        }
    }
}

struct ContentFilter {
    enum FilterResult {
        case clean(String)
        case flagged(reason: String)
    }

    // Patterns that must never appear in output sent to the screen.
    // Extend this list based on your app's domain and age rating.
    private static let blockedPatterns: [NSRegularExpression] = [
        // Phone number patterns (PII leakage prevention)
        try! NSRegularExpression(pattern: #"\b\d{3}[-.\s]?\d{3}[-.\s]?\d{4}\b"#),
        // Credit card number patterns
        try! NSRegularExpression(pattern: #"\b(?:\d[- ]?){13,16}\b"#)
    ]

    private static let serverBlocklist: [String] = [
        // Loaded from your backend at launch; hard-coded fallback here.
        "[BLOCKED_TERM_1]",
        "[BLOCKED_TERM_2]"
    ]

    static func scan(_ text: String) -> FilterResult {
        let lowered = text.lowercased()

        for term in serverBlocklist where lowered.contains(term) {
            return .flagged(reason: "Response contained disallowed content and was not shown.")
        }

        let range = NSRange(text.startIndex..., in: text)
        for pattern in blockedPatterns {
            if pattern.firstMatch(in: text, range: range) != nil {
                return .flagged(reason: "Response contained sensitive data and was not shown.")
            }
        }

        return .clean(text)
    }
}

let rawReply = try await service.send(userMessage: clean)

switch ContentFilter.scan(rawReply) {
case .clean(let safeText):
    messages.append(.assistant(safeText))
case .flagged(let reason):
    // Show a placeholder rather than the blocked text
    messages.append(.assistantFiltered(reason))
    // Log the event for audit purposes
    AuditLogger.record(event: .responseFiltered(reason: reason, inputHash: clean.sha256()))
}

actor BlocklistStore {
    private(set) var terms: [String] = []

    func load(from url: URL) async throws {
        let (data, _) = try await URLSession.shared.data(from: url)
        let decoded = try JSONDecoder().decode([String].self, from: data)
        terms = decoded
    }
}

